-- ESTUDIAR · Fase E-2 (PORTUGUÉS) — A1+A2 (unidades 1-12), SOLO DATOS.
-- La tabla study_theory y las RPCs get_study_theory/submit_study_quiz ya viven
-- desde la mig 178 y son course-agnósticas POR CONSTRUCCIÓN: derivan el curso de
-- la propia unidad (v_unit.course_id), no de un idioma fijo. Aquí
-- solo se insertan los 12 temas de pt (upsert idempotente por (course_id,
-- unit_order) → el INGLÉS queda intacto, es otro course_id).
-- NO toca motor FSRS, economía, gating, certificación ni los otros 5 idiomas.
-- El quiz sigue siendo FORMATIVO (jz_grade, sin XP/oro).


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 1, 'A1', 'Hola y mucho gusto', 'Vas a saludar en portugués (Oi, tudo bem?), presentarte con el verbo SER y dominar la clave: «você» se conjuga en 3ª persona.', '[{"heading": "Saludar y responder", "body": "En Brasil el saludo más común es «Oi» (informal) u «Olá». Casi siempre va seguido de «Tudo bem?» (¿todo bien?). La respuesta típica es repetir: «Tudo bem!». Para «mucho gusto» se dice «Prazer» o «Muito prazer».", "bullets": ["«Oi» = hola (informal); «Olá» = hola (neutro)", "«Tudo bem?» pregunta y «Tudo bem!» responde", "«Prazer» / «Muito prazer» = mucho gusto"]}, {"heading": "Presentarte con el verbo SER", "body": "Para decir quién eres usas el verbo SER: «eu sou» (yo soy), «você é» (tú eres), «nós somos» (nosotros somos). En Brasil es natural poner artículo ante el nombre propio: «Eu sou a Ana», «Eu sou o Pedro».", "bullets": ["eu sou · você é · nós somos", "«Eu sou a Ana» / «Eu sou o Pedro»", "«Sou de...» dice de dónde eres"]}, {"heading": "La clave: «você» va en 3ª persona", "body": "«Você» significa ''tú'', pero gramaticalmente funciona como ''usted'': el verbo va en 3ª persona. Se dice «você é», nunca «você és». Es el error número uno del hispanohablante, porque en español ''tú eres'' lleva la forma de 2ª persona.", "bullets": ["você = ''tú'', pero verbo de 3ª persona", "Correcto: «você é» · Incorrecto: «você és»", "Piensa en «você» como ''usted'' al conjugar"]}]'::jsonb, '[{"pt": "Oi! Eu sou a Ana. Prazer!", "es": "¡Hola! Soy Ana. ¡Mucho gusto!", "text": "Oi! Eu sou a Ana. Prazer!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ae9594b4-942b-553f-9ee0-5ce9fc205549.mp3"}, {"pt": "Você é o Pedro? — Sou, sim!", "es": "¿Tú eres Pedro? — ¡Sí, soy yo!", "text": "Você é o Pedro? — Sou, sim!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ff183f46-0b83-5484-b74a-d50e48114a5b.mp3"}, {"pt": "Oi, tudo bem? — Tudo bem, e você?", "es": "Hola, ¿qué tal? — Bien, ¿y tú?", "text": "Oi, tudo bem? — Tudo bem, e você?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2072513b-9fbf-5482-bb27-268a7c6b5b1c.mp3"}, {"pt": "Nós somos do México. Muito prazer!", "es": "Nosotros somos de México. ¡Mucho gusto!", "text": "Nós somos do México. Muito prazer!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/596e1614-b81f-5dc6-9283-8636cb3d3af7.mp3"}]'::jsonb, '[{"title": "Conjugar «você» como el ''tú'' español", "body": "Decir «você és» calcando ''tú eres''. En portugués «você» exige 3ª persona: «você é». La forma «és» existe, pero acompaña a «tu», no a «você»."}, {"title": "«Mucho gusto» ≠ «muito gosto»", "body": "«Gosto» significa ''sabor'' o ''yo gusto (de algo)''. Para presentarte se dice «Prazer» o «Muito prazer». «Muito gosto» suena a error y no se usa como saludo."}, {"title": "Traducir literal «¿cómo estás?»", "body": "El saludo cotidiano brasileño no es una traducción de ''¿cómo estás?'': lo natural es «Tudo bem?» o «Tudo bom?», y se responde igual: «Tudo bem!»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Te presentan a alguien y quieres decir «mucho gusto». ¿Qué dices?", "options": ["Muito prazer", "Muito gosto", "Por favor"], "answer": "Muito prazer", "id": "u1q1"}, {"type": "multiple_choice", "prompt": "Completa con la forma correcta: «Você ___ meu amigo.»", "options": ["é", "és", "sou"], "answer": "é", "id": "u1q2"}, {"type": "cloze", "prompt": "Escribe la forma correcta del verbo SER (1 palabra):", "text": "Você ___ do Brasil?", "answer": "é", "accepted": ["é"], "id": "u1q3"}, {"type": "cloze", "prompt": "Escribe la forma correcta del verbo SER para «nosotros» (1 palabra):", "text": "Nós ___ estudantes.", "answer": "somos", "accepted": ["somos"], "id": "u1q4"}, {"type": "cloze", "prompt": "Escribe la forma correcta del verbo SER para «yo» (1 palabra):", "text": "Eu ___ a Maria. Prazer!", "answer": "sou", "accepted": ["sou"], "id": "u1q5"}]'::jsonb)
