insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 3, 'A1', 'Mi día a día', 'Aprende a hablar de tu rutina diaria en portugués: los verbos en -AR en presente (morar, trabalhar, estudar) y la regla de oro de «gostar», que SIEMPRE lleva «de» — «gosto de café», «gosto de estudar».', '[{"heading": "Verbos en -AR en presente", "body": "Los verbos en -AR se conjugan casi como en español: se quita -AR y se añade la terminación. Con «você» (la forma más usada para «tú» en Brasil) el verbo va en 3ª persona, como «usted».", "bullets": ["eu moro, trabalho, estudo (yo)", "você mora, trabalha, estuda (tú/usted)", "nós moramos, trabalhamos, estudamos (nosotros)", "eles/elas moram, trabalham, estudam (ellos/ellas)"]}, {"heading": "«Gostar» siempre con «de»", "body": "En portugués no se dice «me gusta»: la persona es el sujeto. Se dice «eu gosto de…» y el «de» es OBLIGATORIO siempre, también antes de otro verbo: «gosto de trabalhar». Con artículo, «de» se contrae: de + o = do, de + a = da.", "bullets": ["eu gosto de café (me gusta el café)", "você gosta de música? (¿te gusta la música?)", "gosto de estudar (me gusta estudiar)", "gosto do Brasil, gosto da praia (do = de+o, da = de+a)"]}, {"heading": "Tu rutina diaria", "body": "Con pocos verbos en -AR ya puedes contar tu día: acordar (despertarse), tomar café da manhã (desayunar), trabalhar, estudar, almoçar (almorzar), jantar (cenar), descansar. Ojo: «trabalhar» se escribe con LH (trabalhar, trabalho), nunca con J.", "bullets": ["Eu acordo cedo. (Me despierto temprano.)", "Eu trabalho de manhã. (Trabajo por la mañana.)", "Nós almoçamos ao meio-dia. (Almorzamos al mediodía.)", "Eu janto em casa. (Ceno en casa.)"]}]'::jsonb, '[{"pt": "Eu gosto de café de manhã.", "es": "Me gusta el café por la mañana.", "text": "Eu gosto de café de manhã.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3b79714b-8756-5b45-a291-31f92ded5c1f.mp3"}, {"pt": "Você trabalha ou estuda?", "es": "¿Trabajas o estudias?", "text": "Você trabalha ou estuda?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ed67a8ca-2255-5e47-9feb-ae72308e9873.mp3"}, {"pt": "Nós moramos em São Paulo.", "es": "Vivimos en São Paulo.", "text": "Nós moramos em São Paulo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/297e3cbc-ebd8-550c-92b8-3e07ee80a52d.mp3"}, {"pt": "Eu gosto de estudar português à noite.", "es": "Me gusta estudiar portugués por la noche.", "text": "Eu gosto de estudar português à noite.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/31eca189-b642-5e3f-b604-5f0d34833534.mp3"}]'::jsonb, '[{"title": "Omitir «de» después de «gostar»", "body": "El hispanohablante calca «me gusta el café» y dice «gosto café» ❌. En portugués «gostar» SIEMPRE pide «de»: «gosto de café», «gosto de dançar». Sin «de» la frase está mal, incluso antes de otro verbo."}, {"title": "Buscar un «me gusta» con pronombre", "body": "No existe «me gosta» ❌. La estructura es al revés que en español: la persona es el sujeto. Yo → «eu gosto de…», ¿a ti? → «você gosta de…?». Nada de «me/te/le» delante del verbo."}, {"title": "Escribir «trabajar» a la española", "body": "En portugués es «trabalhar», con LH (suena como la LL de algunas zonas): eu trabalho, você trabalha. Escribir «trabajar» o «trabajo» con J es un calco del español y no existe en portugués."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la frase correcta en portugués para decir «Me gusta el café».", "options": ["Eu gosto de café.", "Eu gosto café.", "Me gosta o café."], "answer": "Eu gosto de café.", "id": "u3q1"}, {"type": "cloze", "prompt": "Completa con la palabra que falta.", "text": "Eu gosto ___ música brasileira.", "answer": "de", "accepted": ["de", "da"], "id": "u3q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta con «você»?", "options": ["Você mora em Lima.", "Você moro em Lima.", "Você moramos em Lima."], "answer": "Você mora em Lima.", "id": "u3q3"}, {"type": "cloze", "prompt": "Completa con el verbo «trabalhar» conjugado para «eu».", "text": "Eu ___ de manhã.", "answer": "trabalho", "accepted": ["trabalho"], "id": "u3q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «Me gusta estudiar»?", "options": ["Gosto de estudar.", "Gosto estudar.", "Me gusta estudar."], "answer": "Gosto de estudar.", "id": "u3q5"}]'::jsonb)
