  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 5, 'A1', '¿Dónde queda?', 'Vas a preguntar dónde queda algo como un brasileño (con ficar) y a usar las contracciones no/na/do/da: el español solo contrae en «del» y «al», el portugués lo hace siempre con el artículo definido.', '[{"heading": "FICAR: el verbo de la ubicación", "body": "Para decir dónde queda algo fijo (un banco, una plaza), el brasileño usa «ficar»: «Onde fica o banco?». «Estar» también existe y se entiende, pero «ficar» es lo natural para lugares que no se mueven.", "bullets": ["«Onde fica…?» = ¿dónde queda…?", "Lugares fijos → ficar suena más natural", "«O hotel fica no centro.»"]}, {"heading": "Contracciones obligatorias: no, na, do, da", "body": "En portugués, «em» y «de» se funden SIEMPRE con el artículo definido (o, a): em + o = no, em + a = na, de + o = do, de + a = da. Decir «em o centro» es error; lo correcto es «no centro».", "bullets": ["em + o = no («no centro»)", "em + a = na («na praça»)", "de + o = do («ao lado do banco»)", "de + a = da («perto da escola»)"]}, {"heading": "Direcciones básicas", "body": "Con cuatro expresiones ya puedes ubicar casi todo: «perto de» (cerca de), «longe de» (lejos de), «ao lado de» (al lado de) y «em frente» (enfrente). Recuerda contraer el «de» con el artículo que sigue.", "bullets": ["perto de = cerca de", "longe de = lejos de", "ao lado de = al lado de", "em frente = enfrente"]}]'::jsonb, '[{"pt": "Onde fica a farmácia?", "es": "¿Dónde queda la farmacia?", "text": "Onde fica a farmácia?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8695b510-b366-584a-9fa4-0af1f2fe1c94.mp3"}, {"pt": "O banco fica no centro.", "es": "El banco queda en el centro.", "text": "O banco fica no centro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/469bbc36-0abb-5f79-bcb1-61641f298f05.mp3"}, {"pt": "A escola fica perto da praça.", "es": "La escuela queda cerca de la plaza.", "text": "A escola fica perto da praça.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a0c510b4-3601-5244-a069-70160c833dae.mp3"}, {"pt": "O mercado fica ao lado do hotel.", "es": "El mercado queda al lado del hotel.", "text": "O mercado fica ao lado do hotel.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/94ad14b3-4899-54d4-bf61-9240195caedc.mp3"}]'::jsonb, '[{"title": "«Em o centro» no existe", "body": "El hispanohablante dice «en el centro» con dos palabras y calca «em o centro». En portugués la contracción es obligatoria: «no centro», «na praça». Escribir «em o» o «de a» siempre es error."}, {"title": "¿«Está» o «fica»?", "body": "«Onde está o banco?» se entiende, pero suena a que el banco podría moverse. Para ubicación fija, el brasileño pregunta «Onde fica?». Reserva «estar» para cosas o personas que cambian de lugar."}, {"title": "«Perto de» + artículo también contrae", "body": "No basta con aprender «perto de»: si sigue un sustantivo con artículo, contrae. «Perto de a escola» ✗ → «perto da escola» ✓; «ao lado de o banco» ✗ → «ao lado do banco» ✓."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «en el centro» en portugués?", "options": ["no centro", "em o centro", "em no centro"], "answer": "no centro", "id": "u5q1"}, {"type": "cloze", "prompt": "Completa con la contracción de em + a.", "text": "O mercado fica ___ rua principal.", "answer": "na", "accepted": ["na"], "id": "u5q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma más natural en Brasil de preguntar dónde queda el banco?", "options": ["Onde fica o banco?", "Onde vai o banco?", "Onde tem lugar o banco?"], "answer": "Onde fica o banco?", "id": "u5q3"}, {"type": "cloze", "prompt": "Completa con la contracción de de + o.", "text": "A farmácia fica ao lado ___ mercado.", "answer": "do", "accepted": ["do"], "id": "u5q4"}, {"type": "multiple_choice", "prompt": "¿Qué significa «perto de»?", "options": ["cerca de", "lejos de", "detrás de"], "answer": "cerca de", "id": "u5q5"}]'::jsonb)
