insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 6, 'A1', 'Tiempo libre', 'Aprende los días de la semana brasileños (que se cuentan desde el domingo, no desde el lunes), habla de tus pasatiempos con «gostar de» y planea tu fin de semana.', '[{"heading": "Los días se cuentan desde el DOMINGO", "body": "En portugués los días laborables se numeran empezando por el domingo como día 1. Por eso «segunda-feira» es el día 2 de la semana: el LUNES, no el martes. Van siempre en minúscula.", "bullets": ["segunda-feira = lunes · terça-feira = martes", "quarta = miércoles · quinta = jueves · sexta = viernes", "En el habla se corta el «-feira»: «na segunda»", "En minúscula, salvo a principio de frase: «na segunda»"]}, {"heading": "Pasatiempos con «gostar DE»", "body": "Para decir lo que te gusta hacer usa «gostar de + infinitivo»: «Eu gosto de nadar». El «de» es obligatorio; en español decimos «me gusta nadar» sin preposición, por eso se olvida fácil.", "bullets": ["gosto de ler = me gusta leer", "Você gosta de cozinhar? = ¿te gusta cocinar?", "Sin «de» la frase queda mal: «gosto nadar» ❌"]}, {"heading": "El fin de semana", "body": "«Fim de semana» es masculino: se dice «o fim de semana» y «NO fim de semana» (em + o = no). «Sábado» y «domingo» sí se parecen al español y no llevan «-feira».", "bullets": ["no fim de semana = el fin de semana", "sábado e domingo: sin «-feira»", "O que você faz no sábado?"]}]'::jsonb, '[{"pt": "Na segunda-feira eu trabalho.", "es": "El lunes trabajo.", "text": "Na segunda-feira eu trabalho.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ff2d47c8-a171-5b1c-9b47-22a298329b99.mp3"}, {"pt": "Eu gosto de nadar no verão.", "es": "Me gusta nadar en verano.", "text": "Eu gosto de nadar no verão.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7b3024f3-9fa1-5726-870f-ba630082737f.mp3"}, {"pt": "No fim de semana eu descanso.", "es": "El fin de semana descanso.", "text": "No fim de semana eu descanso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ca28125e-9e35-5a20-a342-b7a61c54dd9f.mp3"}, {"pt": "Na sexta-feira nós saímos com amigos.", "es": "El viernes salimos con amigos.", "text": "Na sexta-feira nós saímos com amigos.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0ab55ce1-2d4d-5e8f-8ac9-6ee929ea7bf4.mp3"}]'::jsonb, '[{"title": "«Segunda» NO es martes", "body": "Como los días se cuentan desde el domingo, «segunda-feira» es LUNES y «terça-feira» es MARTES. Si mapeas «segunda = segundo día laboral» al estilo español, llegarás un día tarde a todo."}, {"title": "Olvidar el «de» de «gostar»", "body": "En portugués siempre es «gostar DE alguma coisa»: «gosto de música», «gosto de correr». Decir «gosto música» o «gosto correr» es un error típico de hispanohablante."}, {"title": "«En el fin de semana» → «NO fim de semana»", "body": "No traduzcas palabra por palabra: «em + o» se contrae en «no». Se dice «no fim de semana», nunca «em o fim de semana»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué día es «terça-feira»?", "options": ["martes", "jueves", "domingo"], "answer": "martes", "id": "u6q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «miércoles» en portugués?", "options": ["quarta-feira", "quinta-feira", "segunda-feira"], "answer": "quarta-feira", "id": "u6q2"}, {"type": "cloze", "prompt": "Completa con la preposición que falta.", "text": "Eu gosto ___ nadar no verão.", "answer": "de", "accepted": ["de"], "id": "u6q3"}, {"type": "cloze", "prompt": "Completa con el día que corresponde a «lunes».", "text": "Na ___ eu começo a trabalhar.", "answer": "segunda-feira", "accepted": ["segunda-feira", "segunda"], "id": "u6q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «el fin de semana» (con la contracción correcta)?", "options": ["no fim de semana", "em o fim de semana", "na fim de semana"], "answer": "no fim de semana", "id": "u6q5"}]'::jsonb)
