insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 7, 'A2', 'El pasado: lo que hice', 'Aprende el pretérito perfeito: el tiempo del pasado ya ocurrido en portugués. Verás las terminaciones regulares (falei, comi, abri) y los irregulares clave (fui, fiz, tive, estive), y por qué en pt-BR se dice «hoje eu falei» y no «tenho falado».', '[{"heading": "Regulares: cambia la terminación", "body": "Para decir lo que ya hiciste (con «eu»), quita la terminación del infinitivo y añade la del pasado: -ar → -ei, -er → -i, -ir → -i. Es muy parecido al español «hablé, comí, abrí».", "bullets": ["falar → eu falei (hablé)", "comer → eu comi (comí)", "abrir → eu abri (abrí)"]}, {"heading": "Irregulares clave: fui, fiz, tive, estive", "body": "Los verbos más usados son irregulares, como en español. Ir y ser comparten forma: «fui» significa ''fui'' de ir y de ser. Memoriza estas cuatro formas con «eu»: son cortas y aparecen todo el tiempo.", "bullets": ["ir / ser → eu fui", "fazer → eu fiz (hice)", "ter → eu tive (tuve)", "estar → eu estive (estuve)"]}, {"heading": "Para lo que YA pasó, usa el perfeito", "body": "En pt-BR, si la acción ya terminó, usa el perfeito, incluso si fue hoy: «Hoje eu falei com ela». No traduzcas el español «he hablado» como «tenho falado»: esa forma existe, pero significa otra cosa (repetición últimamente).", "bullets": ["Hoy hablé → Hoje eu falei", "Esta mañana comí → Hoje de manhã eu comi", "«Tenho falado» = vengo hablando (repetido)"]}]'::jsonb, '[{"pt": "Ontem eu falei com minha avó.", "es": "Ayer hablé con mi abuela.", "text": "Ontem eu falei com minha avó.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/87f97af5-cef4-566c-83cd-0f326b2efb2c.mp3"}, {"pt": "Eu comi feijoada no domingo.", "es": "Comí feijoada el domingo.", "text": "Eu comi feijoada no domingo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/391db310-cd01-5c5e-ac62-af1329363ba7.mp3"}, {"pt": "Ela fez um bolo delicioso para a festa.", "es": "Ella hizo un pastel delicioso para la fiesta.", "text": "Ela fez um bolo delicioso para a festa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3e4ba9f0-1408-521e-87c4-01ecbc3dc8c1.mp3"}, {"pt": "Eu tive uma reunião e depois fui ao mercado.", "es": "Tuve una reunión y después fui al mercado.", "text": "Eu tive uma reunião e depois fui ao mercado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/561becc9-aadb-55ba-8990-6c2598e3f09a.mp3"}]'::jsonb, '[{"title": "«hice» NO es «fazi»", "body": "El calco del español lleva a inventar «fazi», que no existe. La forma correcta de fazer con «eu» es «fiz»: «Eu fiz o jantar» (hice la cena). Corta y sin terminación visible."}, {"title": "«Tive» soy yo; «teve» es él o ella", "body": "El error real no es inventar «tevi», sino confundir la persona: «Eu tive uma boa ideia» (yo) frente a «Ele teve uma boa ideia» (él). Lo mismo con «estive» (yo) y «esteve» (él)."}, {"title": "No uses «tenho falado» como «he hablado»", "body": "En español dices «hoy he hablado con él»; en pt-BR eso es perfeito simple: «hoje eu falei com ele». «Tenho falado» significa que vienes hablando repetidamente en los últimos tiempos, no una acción puntual terminada."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Ayer yo ___ la cena.» → «Ontem eu ___ o jantar.»", "options": ["fiz", "fazi", "fez"], "answer": "fiz", "id": "u7q1"}, {"type": "cloze", "prompt": "Completa con el pretérito perfeito de ''ter'' (eu).", "text": "Eu ___ uma boa ideia ontem.", "answer": "tive", "accepted": ["tive"], "id": "u7q2"}, {"type": "multiple_choice", "prompt": "Elige la forma correcta: «Yo ___ al mercado ayer.» → «Eu ___ ao mercado ontem.»", "options": ["fui", "foi", "ia"], "answer": "fui", "id": "u7q3"}, {"type": "cloze", "prompt": "Completa con el pretérito perfeito de ''falar'' (eu).", "text": "Hoje eu ___ com meu professor.", "answer": "falei", "accepted": ["falei"], "id": "u7q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice en pt-BR «Hoy hablé con mi madre» (acción ya terminada)?", "options": ["Hoje eu falei com minha mãe.", "Hoje eu tenho falado com minha mãe.", "Hoje eu falava com minha mãe."], "answer": "Hoje eu falei com minha mãe.", "id": "u7q5"}]'::jsonb)
