insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 8, 'A2', 'Planes y futuro', 'En portugués hablado, el futuro se dice con «ir + infinitivo» pegado, SIN «a»: «vou viajar», «você vai estudar». Aprende a conjugar IR en presente (vou, vai, vamos, vão) y a invitar con «vamos + infinitivo». El futuro sintético («viajarei») existe, pero en el habla es raro.', '[{"heading": "El verbo IR en presente", "body": "IR es irregular y es la llave del futuro coloquial. Memoriza sus cuatro formas del habla: eu vou, você/ele/ela vai, nós vamos, vocês/eles/elas vão. Con «tu» (algunas regiones) se usa «vais» poco; en Brasil domina «você vai».", "bullets": ["eu vou · você/ele/ela vai", "nós vamos · vocês/eles/elas vão", "«a gente vai» = nosotros (coloquial)"]}, {"heading": "Futuro con «ir + infinitivo» (sin «a»)", "body": "Para hablar del futuro, une IR directamente al infinitivo: «vou viajar», «ela vai estudar», «eles vão trabalhar». En español decimos «voy A viajar», pero en portugués ese «a» NO se usa entre ir y el infinitivo. Es la forma normal del habla.", "bullets": ["vou viajar = voy a viajar", "Nunca «vou a viajar» con infinitivo", "Ojo: «ir a» sí existe con LUGARES («vou ao mercado»)", "Invitación: «Vamos sair?» = ¿salimos?"]}, {"heading": "¿Y «viajarei»? El futuro sintético", "body": "El futuro con terminaciones («viajarei», «estudaremos») existe y lo verás escrito: noticias, textos formales, canciones. Pero en la conversación diaria brasileña casi nadie lo usa. Para hablar, quédate con «ir + infinitivo»; para leer, basta con reconocerlo.", "bullets": ["«viajarei» = escrito/formal", "«vou viajar» = habla de todos los días", "Reconócelo al leer, no lo fuerces al hablar"]}]'::jsonb, '[{"pt": "Amanhã eu vou viajar para o Rio.", "es": "Mañana voy a viajar a Río.", "text": "Amanhã eu vou viajar para o Rio.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5ac5e359-4b1a-585e-952e-d136e90fb241.mp3"}, {"pt": "Você vai estudar hoje à noite?", "es": "¿Vas a estudiar hoy por la noche?", "text": "Você vai estudar hoje à noite?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3c6c2db5-6ffb-5627-9d45-754e274e7acf.mp3"}, {"pt": "Nós vamos comprar os ingressos na sexta.", "es": "Vamos a comprar las entradas el viernes.", "text": "Nós vamos comprar os ingressos na sexta.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/50099b6f-c0c6-5320-8648-ee2e3d73ee9a.mp3"}, {"pt": "Eles vão chegar tarde, então vamos jantar sem eles.", "es": "Van a llegar tarde, así que vamos a cenar sin ellos.", "text": "Eles vão chegar tarde, então vamos jantar sem eles.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fb4415ba-ac25-5b25-9bed-f3c0e539f2fd.mp3"}]'::jsonb, '[{"title": "El «a» intruso: «vou a fazer» ✗", "body": "El calco n.º 1 del hispanohablante: «voy a hacer» → «vou a fazer». En portugués, entre IR y el infinitivo no va nada: «vou fazer», «vai comer», «vamos sair». Si te sale el «a», bórralo."}, {"title": "No confundas con «ir a + lugar»", "body": "La regla «sin a» es solo con INFINITIVOS. Con lugares, la preposición sí aparece, a menudo contraída con el artículo: «vou ao mercado», «vamos à praia». O sea: «vou viajar», pero «vou ao Brasil»."}, {"title": "«Eles vão» + infinitivo, sin «a»", "body": "«Eles vão» ya significa «ellos van»; para el futuro añade el infinitivo directo: «eles vão viajar». No digas «eles vão a viajar» ni uses «van» español: la forma es «vão», con ã nasal."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «voy a trabajar mañana»?", "options": ["Vou trabalhar amanhã.", "Vou a trabalhar amanhã.", "Vou trabalho amanhã."], "answer": "Vou trabalhar amanhã.", "id": "u8q1"}, {"type": "multiple_choice", "prompt": "Elige la forma correcta de IR para «vocês».", "options": ["vão", "vamos", "vou"], "answer": "vão", "id": "u8q2"}, {"type": "cloze", "prompt": "Completa con el presente de ''ir'' (nós).", "text": "Nós ___ sair hoje à noite.", "answer": "vamos", "accepted": ["vamos"], "id": "u8q3"}, {"type": "cloze", "prompt": "Completa con el presente de ''ir'' (ela).", "text": "Ela ___ estudar depois do jantar.", "answer": "vai", "accepted": ["vai"], "id": "u8q4"}, {"type": "multiple_choice", "prompt": "En una conversación normal en Brasil, ¿cuál es la forma más natural de decir «viajaré el domingo»?", "options": ["Vou viajar no domingo.", "Viajarei no domingo.", "Vou a viajar no domingo."], "answer": "Vou viajar no domingo.", "id": "u8q5"}]'::jsonb)
