insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 9, 'A2', 'De viaje', 'En Brasil el transporte se «pega»: pegar o ônibus, o metrô, um táxi. Aprende el vocabulario del viaje con sus falsos amigos (a passagem, a rodoviária, embarcar) y a preguntar horarios: «A que horas sai o ônibus?».', '[{"heading": "Pegar: el verbo del transporte", "body": "El brasileño «pega» el transporte: pegar o ônibus, pegar o metrô, pegar um táxi. Es lo más natural en el habla diaria. «Tomar um táxi» también se oye, pero «coger» no se usa en Brasil para esto.", "bullets": ["Vou pegar o ônibus. = Voy a tomar el autobús.", "Peguei um táxi ontem. = Tomé un taxi ayer.", "«Ônibus» es masculino y lleva acento: o ônibus."]}, {"heading": "Falsos amigos del viaje", "body": "«A passagem» es el billete de autobús o avión; para viajes largos nadie dice «bilhete» (esa palabra existe, pero se usa más para el metro o una notita). «A rodoviária» es la estación de autobuses. «Embarcar» es subir al transporte.", "bullets": ["Comprar a passagem = comprar el billete.", "A rodoviária = la estación de autobuses.", "Embarcar = subir al autobús o avión."]}, {"heading": "Preguntar horarios", "body": "Para preguntar horarios usa «A que horas...?» con los verbos sair (salir) y chegar (llegar): «A que horas sai o ônibus para o Rio?», «A que horas chega o trem?». La respuesta usa «às»: «Sai às dez».", "bullets": ["A que horas sai...? = ¿A qué hora sale...?", "A que horas chega...? = ¿A qué hora llega...?", "Sai às dez. = Sale a las diez."]}]'::jsonb, '[{"pt": "Vou pegar o ônibus das oito.", "es": "Voy a tomar el autobús de las ocho.", "text": "Vou pegar o ônibus das oito.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/77df84cf-bc91-53ee-9c53-bfd445c4cbe7.mp3"}, {"pt": "Comprei a passagem na rodoviária.", "es": "Compré el billete en la estación de autobuses.", "text": "Comprei a passagem na rodoviária.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/99e4c9f0-32e8-5331-b043-512b9d9eb517.mp3"}, {"pt": "A que horas sai o ônibus para o Rio?", "es": "¿A qué hora sale el autobús para Río?", "text": "A que horas sai o ônibus para o Rio?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e377c610-8072-521d-af57-0aca88a96c27.mp3"}, {"pt": "Vamos embarcar às dez da manhã.", "es": "Vamos a embarcar a las diez de la mañana.", "text": "Vamos embarcar às dez da manhã.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7a0f0ff2-e077-5938-9f92-c9b4e5d29aa9.mp3"}]'::jsonb, '[{"title": "«Coger el autobús» no funciona en Brasil", "body": "«Coger» no existe en portugués: el verbo del día a día es «pegar» (pegar o ônibus, pegar o metrô). En Brasil también se oye «tomar»."}, {"title": "«Passagem», no «billete»", "body": "El billete de autobús o avión es «a passagem» (femenino): «comprar a passagem». «Bilhete» existe en portugués, pero se usa más para el billete del metro o para una notita escrita, no para viajes de larga distancia."}, {"title": "«Ônibus» es masculino, con Ô", "body": "Se escribe «ônibus» con acento circunflejo y es masculino: «o ônibus», «um ônibus». No cambia en plural: «os ônibus». No digas «la ônibus» ni «autobús»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo dice un brasileño «tomar el autobús» en su forma más natural?", "options": ["pegar o ônibus", "coger o ônibus", "andar de ônibus"], "answer": "pegar o ônibus", "id": "u9q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se llama el billete de autobús o avión en Brasil?", "options": ["a passagem", "o ingresso", "a entrada"], "answer": "a passagem", "id": "u9q2"}, {"type": "multiple_choice", "prompt": "¿Dónde compras la passagem para viajar en autobús a otra ciudad?", "options": ["na rodoviária", "na padaria", "na livraria"], "answer": "na rodoviária", "id": "u9q3"}, {"type": "cloze", "prompt": "Completa con el verbo del transporte en infinitivo (vale la forma más natural u otra correcta).", "text": "Precisamos ___ um táxi para o aeroporto.", "answer": "pegar", "accepted": ["pegar", "tomar", "chamar", "pedir"], "id": "u9q4"}, {"type": "cloze", "prompt": "Completa la pregunta de horario con el verbo «salir» conjugado (presente, él/ello).", "text": "A que horas ___ o ônibus para São Paulo?", "answer": "sai", "accepted": ["sai", "parte"], "id": "u9q5"}]'::jsonb)
