insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 10, 'A2', 'Comer fuera y comprar', 'Aprende a pedir en un restaurante brasileño con «Eu vou querer…», a pedir la cuenta, a hablar del garçom y la gorjeta, y a esquivar los falsos amigos clásicos de la mesa: esquisito, sobremesa y troco.', '[{"heading": "Pedir en el restaurante", "body": "Para pedir comida, lo más natural en Brasil es «Eu vou querer…» (literalmente ''voy a querer''). También sirve «Eu queria…». Al terminar, pides la cuenta con «A conta, por favor».", "bullets": ["«Eu vou querer uma pizza» = pido una pizza", "«Eu queria um suco» suena amable", "«A conta, por favor» cierra la comida"]}, {"heading": "El personal y la propina", "body": "El camarero es «o garçom» (palabra de origen francés). La propina es «a gorjeta»: en Brasil suele venir como un 10% ya sumado en la cuenta, llamado «os dez por cento».", "bullets": ["o garçom = el camarero", "a gorjeta = la propina", "El 10% suele venir en la cuenta"]}, {"heading": "Falsos amigos de la mesa", "body": "Ojo: «esquisito» significa RARO, nunca delicioso; para elogiar di «delicioso» o «uma delícia». «A sobremesa» es el postre, no la charla de después. «O troco» es el cambio o vuelto.", "bullets": ["esquisito = raro, extraño", "delicioso / uma delícia = exquisito", "Al comprar: «Quanto custa?» o «Quanto é?»", "«Aceita cartão?» · «Vou pagar em dinheiro»"]}]'::jsonb, '[{"pt": "Eu vou querer o frango com arroz, por favor.", "es": "Voy a pedir el pollo con arroz, por favor.", "text": "Eu vou querer o frango com arroz, por favor.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/15e8f32e-9a64-5c73-aead-e09c5dd2216f.mp3"}, {"pt": "A conta, por favor.", "es": "La cuenta, por favor.", "text": "A conta, por favor.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5da02a2d-62d6-5bd3-b04c-24d948876917.mp3"}, {"pt": "O garçom trouxe a sobremesa: pudim de leite.", "es": "El camarero trajo el postre: flan de leche.", "text": "O garçom trouxe a sobremesa: pudim de leite.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c8470dfb-d2f5-5d82-ac58-c97cb1373601.mp3"}, {"pt": "Pode ficar com o troco.", "es": "Puede quedarse con el cambio.", "text": "Pode ficar com o troco.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/81fdb368-fc96-5cca-a7ab-4e2ffba224d2.mp3"}]'::jsonb, '[{"title": "«Esquisito» NO es exquisito", "body": "Si dices que la comida está «esquisita», el garçom entenderá que está RARA o extraña. Para decir que algo está exquisito, usa «delicioso», «uma delícia» o «muito gostoso»."}, {"title": "«Sobremesa» es el postre", "body": "En español, la sobremesa es la charla después de comer. En portugués, «a sobremesa» es el POSTRE (pudim, sorvete…). Si pides «a sobremesa», te traerán algo dulce, no conversación."}, {"title": "«Troco» y «garçom», no calcos del español", "body": "El cambio o vuelto es «o troco» (no «cambio»). Y el camarero es «o garçom»: «camareiro» no se usa así en Brasil."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «el postre» en portugués?", "options": ["a sobremesa", "o troco", "a gorjeta"], "answer": "a sobremesa", "id": "u10q1"}, {"type": "multiple_choice", "prompt": "Un brasileño prueba tu plato y dice: «Está esquisito». ¿Qué quiere decir?", "options": ["Que está raro", "Que está delicioso", "Que está frío"], "answer": "Que está raro", "id": "u10q2"}, {"type": "multiple_choice", "prompt": "En Brasil, la «gorjeta» del 10%…", "options": ["Suele venir ya sumada en la cuenta", "Se paga siempre aparte y en efectivo", "No existe en los restaurantes"], "answer": "Suele venir ya sumada en la cuenta", "id": "u10q3"}, {"type": "cloze", "prompt": "Completa con la palabra para «el camarero».", "text": "O ___ trouxe o cardápio.", "answer": "garçom", "accepted": ["garçom"], "id": "u10q4"}, {"type": "cloze", "prompt": "Completa con la palabra para «el cambio/vuelto».", "text": "Paguei com uma nota de cinquenta e recebi o ___.", "answer": "troco", "accepted": ["troco"], "id": "u10q5"}]'::jsonb)
