insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 11, 'A2', 'Personas y descripciones', 'Vas a describir cómo es alguien y cómo está hoy, haciendo concordar el adjetivo, y a esquivar los falsos amigos que más vergüenza dan.', '[{"heading": "Ser y estar: aquí juegas con ventaja", "body": "Funcionan casi igual que en español: ser para lo que define a la persona, estar para el estado de ahora. Si te suena bien en español, suele acertar en portugués.", "bullets": ["ser: Ela é alta. Ele é simpático. (característica)", "estar: Ele está cansado. Ela está feliz hoje.", "Presente de ser: eu sou, você é, nós somos", "Presente de estar: eu estou, você está, nós estamos"]}, {"heading": "El adjetivo concuerda con la persona", "body": "Los adjetivos en -o cambian a -a en femenino y suman -s en plural. Los de -e y muchos de consonante no cambian de género, pero los de -or, -ês y -ol sí.", "bullets": ["alto / alta / altos / altas", "No cambian: inteligente, feliz, jovem, fácil", "Sí cambian: trabalhador → trabalhadora, português → portuguesa", "espanhol → espanhola; en plural: elas são inteligentes"]}, {"heading": "Falsos amigos al describir", "body": "Aquí el parecido con el español te traiciona. Tres palabras cambian de significado y una de ellas puede costarte un mal rato.", "bullets": ["embaraçada = enredada; avergonzada es envergonhada o sem graça", "esquisito = raro, extraño (no exquisito)", "brincar = jugar o bromear; saltar es pular", "comprido = largo; largo en portugués significa ancho"]}]'::jsonb, '[{"pt": "Minha irmã é alta e muito simpática.", "es": "Mi hermana es alta y muy simpática.", "text": "Minha irmã é alta e muito simpática.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/75752c7a-8712-5369-babb-8894515cdd21.mp3"}, {"pt": "Ele está cansado hoje, mas é uma pessoa animada.", "es": "Él está cansado hoy, pero es una persona animada.", "text": "Ele está cansado hoje, mas é uma pessoa animada.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0b7b61d9-e37d-5eee-a180-43d8528a9e5b.mp3"}, {"pt": "Fiquei sem graça quando esqueci o nome dele.", "es": "Me dio vergüenza cuando olvidé su nombre.", "text": "Fiquei sem graça quando esqueci o nome dele.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/48e55304-2409-5fa9-892d-2e39106a9205.mp3"}, {"pt": "As crianças estão brincando no parque.", "es": "Los niños están jugando en el parque.", "text": "As crianças estão brincando no parque.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/73a3176f-d751-5293-8581-481a7a3e38e2.mp3"}]'::jsonb, '[{"title": "«Embaraçada» no es embarazada", "body": "«Grávida» es embarazada; «embaraçada» NO lo es (significa enredada). Y para decir que pasaste vergüenza, un brasileño dice «Fiquei envergonhada» o «Fiquei sem graça»."}, {"title": "«Brincar» es jugar, no dar saltos", "body": "«As crianças brincam» = los niños juegan. Para saltar se usa «pular»: «pular a corda» (saltar a la cuerda). Y «brincar com alguém» también significa bromear."}, {"title": "Olvidar la concordancia del adjetivo", "body": "No digas «Ela é alto» ni «Elas são simpático». El adjetivo en -o se mueve con la persona: «Ela é alta», «Elas são simpáticas». Y ojo con los de -or/-ês: «Ela é trabalhadora»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Tu amiga espera un bebé. ¿Cómo lo dices en portugués?", "options": ["Ela está grávida.", "Ela está embaraçada.", "Ela está esquisita."], "answer": "Ela está grávida.", "id": "u11q1"}, {"type": "multiple_choice", "prompt": "¿Qué significa «As crianças estão brincando»?", "options": ["Los niños están jugando.", "Los niños están saltando.", "Los niños están brindando."], "answer": "Los niños están jugando.", "id": "u11q2"}, {"type": "cloze", "prompt": "Completa con el verbo correcto: es una característica suya, no de hoy.", "text": "Meu primo ___ muito engraçado.", "answer": "é", "accepted": ["é"], "id": "u11q3"}, {"type": "cloze", "prompt": "Completa con el verbo correcto: es un estado de hoy (ele).", "text": "Ele ___ cansado hoje.", "answer": "está", "accepted": ["está"], "id": "u11q4"}, {"type": "cloze", "prompt": "Haz concordar el adjetivo «simpático» con «Minha avó».", "text": "Minha avó é muito ___.", "answer": "simpática", "accepted": ["simpática"], "id": "u11q5"}]'::jsonb)
