insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 12, 'A2', 'Saúde, experiências e conselhos', 'Vas a decir qué te duele como lo dice un brasileño, a dar consejos con tacto y a evitar el falso amigo médico que más confusión provoca.', '[{"heading": "El dolor se «tiene con»: estou com dor", "body": "En Brasil no se dice «me duele la cabeza», sino que uno «está con dolor». La fórmula es fija: estar com dor de + parte del cuerpo.", "bullets": ["Estou com dor de cabeça. (me duele la cabeza)", "Estou com dor de garganta / de barriga / nas costas.", "Sirve para otros males: estou com febre, estou com tosse.", "También existe «minha cabeça dói», pero se oye menos."]}, {"heading": "Aconsejar sin imponer: você deveria", "body": "Para sugerir algo con tacto se usa «deveria» (deberías) más el infinitivo. En el habla informal muchos brasileños dicen «devia», con el mismo sentido.", "bullets": ["Você deveria descansar mais.", "Você devia ir ao médico. (más coloquial)", "Experiencias: «Já fui ao médico duas vezes».", "«Nunca tomei esse remédio» · «Você já teve dengue?»"]}, {"heading": "El falso amigo que puede avergonzarte", "body": "«Constipado» no significa lo mismo que en español. Si estás acatarrado, la palabra es «resfriado» o «gripado»; y la forma cambia según quien habla.", "bullets": ["En Brasil, constipado = estreñido (en Portugal significa otra cosa)", "Estou resfriado / Estou resfriada = estoy acatarrado(a)", "Estou gripado(a) para una gripe más fuerte.", "La farmacia es «a farmácia»; la receta, «a receita»."]}]'::jsonb, '[{"pt": "Estou com dor de cabeça desde ontem.", "es": "Me duele la cabeza desde ayer.", "text": "Estou com dor de cabeça desde ontem.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f083d758-6cd0-5822-afb1-1935cc5ee612.mp3"}, {"pt": "Você deveria descansar e beber bastante água.", "es": "Deberías descansar y beber bastante agua.", "text": "Você deveria descansar e beber bastante água.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4d7c7289-3fc9-571e-9b20-5d83d9089227.mp3"}, {"pt": "Ela está resfriada e ficou em casa hoje.", "es": "Ella está acatarrada y se quedó en casa hoy.", "text": "Ela está resfriada e ficou em casa hoje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aa34f416-27a6-5a10-86bd-f8cdc363218c.mp3"}, {"pt": "Já fui ao médico duas vezes este ano.", "es": "Ya fui al médico dos veces este año.", "text": "Já fui ao médico duas vezes este ano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/eaa775d6-b49e-54c6-be4c-e086af0cc8a2.mp3"}]'::jsonb, '[{"title": "«Estou constipado» dice otra cosa", "body": "En Brasil «constipado» significa estreñido. Para decir que estás acatarrado usa «estou resfriado» (o «resfriada») o «estou gripado». En Portugal el uso es el contrario."}, {"title": "Traducir «me duele» palabra por palabra", "body": "«Minha cabeça dói» es gramatical, pero lo que se oye todo el día es «Estou com dor de cabeça». Memoriza la fórmula entera: estar com dor de…"}, {"title": "Poner «que» después de deveria", "body": "No digas «Você deveria que descansar». Tras «deveria» va el verbo en infinitivo, sin nada en medio: «Você deveria descansar»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Estás acatarrado y vas a la farmacia. ¿Qué dices?", "options": ["Estou resfriado.", "Estou constipado.", "Estou embaraçado."], "answer": "Estou resfriado.", "id": "u12q1"}, {"type": "multiple_choice", "prompt": "¿Cómo dice un brasileño que le duele la garganta?", "options": ["Estou com dor de garganta.", "Tenho dolor de garganta.", "Sou com dor de garganta."], "answer": "Estou com dor de garganta.", "id": "u12q2"}, {"type": "cloze", "prompt": "Completa el consejo (você, condicional de dever).", "text": "Você ___ descansar mais.", "answer": "deveria", "accepted": ["deveria", "devia"], "id": "u12q3"}, {"type": "cloze", "prompt": "Completa con la preposición fija de la fórmula del dolor.", "text": "Eu estou ___ dor de cabeça.", "answer": "com", "accepted": ["com"], "id": "u12q4"}, {"type": "cloze", "prompt": "Completa con la palabra que en portugués significa ''acatarrado'' (masculino).", "text": "Ele não foi trabalhar porque está ___.", "answer": "resfriado", "accepted": ["resfriado", "gripado"], "id": "u12q5"}]'::jsonb)
